SELECT player_id
FROM player_analytics
WHERE potential_rating > 80;

SELECT COUNT(player_id) AS drafted_players_2022
FROM drafts
WHERE draft_year = 2022;

SELECT full_name
FROM players
ORDER BY full_name;

SELECT AVG(rating) AS average_rating
FROM scouting_reports
WHERE player_id = 1;

SELECT full_name
FROM players
ORDER BY full_name;
